export type SubjectId = 'maths' | 'history' | 'physics' | 'svt' | 'tech' | 'french' | 'english';

export type QuestionType = 'single' | 'multiple';

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctAnswer: number; // Index of the correct option
  explanation?: string;
}

export interface Topic {
  id: string;
  title: string;
  description: string;
  type: 'quiz' | 'sheet';
  content?: string; // Markdown content for revision sheets
  questions?: Question[]; // Only for quizzes
  difficulty: 1 | 2 | 3;
}

export interface Subject {
  id: SubjectId;
  name: string;
  icon: string;
  color: string;
  topics: Topic[];
}

export interface UserProgress {
  completedTopics: string[]; // List of topic IDs
  quizScores: Record<string, number>; // topicId -> score (0-100)
  totalTimeSpent: number; // in minutes
  streakDays: number;
  lastStudyDate: string;
}

import { UserProgress } from '../types';

const STORAGE_KEY = 'brevet_pwa_progress_v1';

const INITIAL_PROGRESS: UserProgress = {
  completedTopics: [],
  quizScores: {},
  totalTimeSpent: 0,
  streakDays: 0,
  lastStudyDate: new Date().toISOString(),
};

export const getProgress = (): UserProgress => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : INITIAL_PROGRESS;
  } catch (e) {
    console.error('Error reading progress:', e);
    return INITIAL_PROGRESS;
  }
};

export const saveQuizScore = (topicId: string, score: number) => {
  const current = getProgress();

  // Update score only if better
  const existingScore = current.quizScores[topicId] || 0;
  const newScore = Math.max(existingScore, score);

  const updated: UserProgress = {
    ...current,
    quizScores: {
      ...current.quizScores,
      [topicId]: newScore,
    },
    completedTopics: current.completedTopics.includes(topicId) 
      ? current.completedTopics 
      : [...current.completedTopics, topicId]
  };

  saveProgress(updated);
};

export const markSheetRead = (topicId: string) => {
  const current = getProgress();
  if (current.completedTopics.includes(topicId)) return;

  const updated: UserProgress = {
    ...current,
    completedTopics: [...current.completedTopics, topicId],
  };
  saveProgress(updated);
};

const saveProgress = (progress: UserProgress) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  } catch (e) {
    console.error('Error saving progress:', e);
  }
};

