  // Refresh progress when component mounts (in case user returned from a quiz)
  useEffect(() => {
    setProgress(getProgress());
  }, []);

  const totalModules = SUBJECTS.reduce((acc, sub) => acc + sub.topics.length, 0);
  const completedCount = progress.completedTopics.length;
  const percentage = totalModules > 0 ? Math.round((completedCount / totalModules) * 100) : 0;

  return (
    <div className="p-4 pb-24 space-y-6">
      {/* Hero / Progress Section */}
      <section className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl p-6 text-white shadow-lg shadow-blue-900/20">
