import React from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { getSubjectById } from '../data/content';
import { getProgress } from '../services/storageService';
import { ChevronLeft, PlayCircle, FileText, CheckCircle2 } from 'lucide-react';
import clsx from 'clsx';

export const SubjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const subject = getSubjectById(id || '');
  const progress = getProgress();

  if (!subject) {
    return <div className="p-8 text-center text-slate-400">Matière introuvable</div>;
  }

  return (
    <div className="pb-24">
      {/* Header for Subject */}
      <div className={clsx("relative p-6 -mt-0", subject.color)}>
        <button 
          onClick={() => navigate('/')}
          className="absolute top-6 left-4 p-2 bg-black/20 rounded-full hover:bg-black/30 text-white transition-colors"
        >
          <ChevronLeft className="w-6 h-6" />
        </button>
        <div className="mt-8">
          <h1 className="text-3xl font-bold text-white mb-2">{subject.name}</h1>
          <p className="text-white/80 text-sm font-medium">
            {subject.topics.length} modules disponibles
          </p>
        </div>
      </div>

      {/* Topic List */}
      <div className="p-4 space-y-3 -mt-4">
        {subject.topics.map((topic) => {
          const isCompleted = progress.completedTopics.includes(topic.id);
          const score = progress.quizScores[topic.id];

          return (
            <Link
              key={topic.id}
              to={topic.type === 'quiz' ? `/quiz/${topic.id}` : `/sheet/${topic.id}`}
              className="flex items-center gap-4 bg-slate-800 p-4 rounded-xl border border-slate-700 hover:border-slate-600 transition-colors shadow-sm"
            >
              <div className={clsx(
                "w-12 h-12 rounded-full flex items-center justify-center shrink-0",
                isCompleted ? "bg-green-500/10 text-green-500" : "bg-slate-700 text-slate-400"
              )}>
                {isCompleted ? <CheckCircle2 className="w-6 h-6" /> : (
                   topic.type === 'quiz' ? <PlayCircle className="w-6 h-6" /> : <FileText className="w-6 h-6" />
                )}
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-start mb-1">
                    <h3 className="font-semibold text-slate-200 truncate pr-2">{topic.title}</h3>
                    {topic.type === 'quiz' && score !== undefined && (
                        <span className={clsx(
                            "text-xs font-bold px-2 py-0.5 rounded",
                            score >= 80 ? "bg-green-500/20 text-green-400" : "bg-yellow-500/20 text-yellow-400"
                        )}>
                            {score}%
                        </span>
                    )}
                </div>
                <p className="text-xs text-slate-400 truncate">{topic.description}</p>
              </div>
            </Link>
          );
        })}

        {subject.topics.length === 0 && (
            <div className="text-center py-10">
                <p className="text-slate-500">Contenu à venir pour {subject.name}...</p>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { SUBJECTS } from '../data/content';
import { saveQuizScore } from '../services/storageService';
import { X, Check, ArrowRight, RefreshCw, ChevronLeft } from 'lucide-react';
import clsx from 'clsx';

export const QuizSession: React.FC = () => {
  const { topicId } = useParams<{ topicId: string }>();
  const navigate = useNavigate();

  // Find the topic inside subjects
  const topic = SUBJECTS.flatMap(s => s.topics).find(t => t.id === topicId);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);

  // Early exit if invalid topic
  if (!topic || topic.type !== 'quiz' || !topic.questions) {
    return <div className="p-8 text-center text-slate-400">Quiz introuvable</div>;
  }

  const currentQuestion = topic.questions[currentIndex];
  const progressPercent = ((currentIndex + (showResult ? 1 : 0)) / topic.questions.length) * 100;

  const handleOptionClick = (index: number) => {
    if (isAnswered) return;
    setSelectedOption(index);
    setIsAnswered(true);

    if (index === currentQuestion.correctAnswer) {
      setScore(s => s + 1);
    }
  };

  const handleNext = () => {
    if (currentIndex < (topic.questions?.length || 0) - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setShowResult(true);
      const finalScore = Math.round(((score + (selectedOption === currentQuestion.correctAnswer ? 0 : 0)) / topic.questions!.length) * 100);
      saveQuizScore(topic.id, finalScore);
    }
  };

  if (showResult) {
    const finalScore = Math.round((score / topic.questions.length) * 100);
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-2xl p-8 text-center space-y-6">
          <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
             <span className="text-3xl">🎉</span>
          </div>

          <div>
            <h2 className="text-2xl font-bold text-white mb-2">Quiz terminé !</h2>
            <p className="text-slate-400">Tu as complété : <br/><span className="text-blue-400">{topic.title}</span></p>
          </div>

          <div className="py-6 border-y border-slate-800">
             <div className="text-5xl font-black text-white mb-2">{finalScore}%</div>
             <p className="text-sm text-slate-500">Score final</p>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <button 
                onClick={() => navigate(-1)}
                className="w-full py-3 px-4 bg-slate-800 hover:bg-slate-700 text-white rounded-xl font-medium transition-colors"
            >
                Retour
            </button>
            <button 
                onClick={() => window.location.reload()}
                className="w-full py-3 px-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-medium transition-colors flex items-center justify-center gap-2"
            >
                <RefreshCw className="w-4 h-4" /> Réessayer
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      {/* Top Bar */}
      <div className="h-16 px-4 flex items-center justify-between border-b border-slate-800">
        <button onClick={() => navigate(-1)} className="p-2 -ml-2 text-slate-400 hover:text-white">
            <X className="w-6 h-6" />
        </button>
        <div className="text-sm font-medium text-slate-400">
            Question {currentIndex + 1} / {topic.questions.length}
        </div>
        <div className="w-8" /> {/* Spacer */}
      </div>

      {/* Progress Bar */}
      <div className="h-1 bg-slate-900 w-full">
        <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${progressPercent}%` }} />
      </div>

      {/* Question Area */}
      <div className="flex-1 flex flex-col p-6 max-w-2xl mx-auto w-full">
        <h2 className="text-xl md:text-2xl font-bold text-white mb-8 leading-relaxed">
            {currentQuestion.text}
        </h2>

        <div className="space-y-3 flex-1">
            {currentQuestion.options.map((option, idx) => {
                let stateClass = "bg-slate-800 border-slate-700 text-slate-200 hover:border-slate-600";

                if (isAnswered) {
                    if (idx === currentQuestion.correctAnswer) {
                        stateClass = "bg-green-500/10 border-green-500 text-green-400";
                    } else if (idx === selectedOption) {
                        stateClass = "bg-red-500/10 border-red-500 text-red-400";
                    } else {
                        stateClass = "bg-slate-800/50 border-slate-800 text-slate-500";
                    }
                }

                return (
                    <button
                        key={idx}
                        onClick={() => handleOptionClick(idx)}
                        disabled={isAnswered}
                        className={clsx(
                            "w-full p-4 text-left rounded-xl border-2 transition-all duration-200 flex justify-between items-center",
                            stateClass
                        )}
                    >
                        <span className="font-medium">{option}</span>
                        {isAnswered && idx === currentQuestion.correctAnswer && <Check className="w-5 h-5" />}
                        {isAnswered && idx === selectedOption && idx !== currentQuestion.correctAnswer && <X className="w-5 h-5" />}
                    </button>
                );
            })}
        </div>

        {/* Feedback & Navigation Footer */}
        <div className={clsx(
            "mt-8 transition-all duration-300 transform",
            isAnswered ? "translate-y-0 opacity-100" : "translate-y-4 opacity-0 pointer-events-none"
        )}>
            {currentQuestion.explanation && (
                <div className="mb-4 p-4 bg-blue-900/20 rounded-lg border border-blue-800 text-blue-200 text-sm">
                    <strong>Explication :</strong> {currentQuestion.explanation}
                </div>
            )}
            <button 
                onClick={handleNext}
                className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold text-lg shadow-lg shadow-blue-900/20 flex items-center justify-center gap-2"
            >
                {currentIndex === topic.questions.length - 1 ? 'Voir les résultats' : 'Suivant'} <ArrowRight className="w-5 h-5" />
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { SUBJECTS } from '../data/content';
import { markSheetRead } from '../services/storageService';
import { ChevronLeft, CheckCircle } from 'lucide-react';

export const RevisionSheet: React.FC = () => {
  const { topicId } = useParams<{ topicId: string }>();
  const navigate = useNavigate();
  const topic = SUBJECTS.flatMap(s => s.topics).find(t => t.id === topicId);

  useEffect(() => {
    if (topic && topicId) {
      markSheetRead(topicId);
    }
  }, [topic, topicId]);

  if (!topic || !topic.content) {
