// Helper to determine subject color safely
const getSubjectColorClasses = (subjectId: string) => {
  const map: Record<string, { text: string; bg: string; border: string; proseHead: string }> = {
    maths: { text: 'text-blue-400', bg: 'bg-blue-500', border: 'border-blue-500', proseHead: 'prose-headings:text-blue-400' },
    history: { text: 'text-amber-400', bg: 'bg-amber-600', border: 'border-amber-600', proseHead: 'prose-headings:text-amber-400' },
    physics: { text: 'text-purple-400', bg: 'bg-purple-600', border: 'border-purple-600', proseHead: 'prose-headings:text-purple-400' },
    svt: { text: 'text-green-400', bg: 'bg-green-600', border: 'border-green-600', proseHead: 'prose-headings:text-green-400' },
    tech: { text: 'text-slate-400', bg: 'bg-slate-600', border: 'border-slate-500', proseHead: 'prose-headings:text-slate-400' },
    default: { text: 'text-blue-400', bg: 'bg-blue-600', border: 'border-blue-600', proseHead: 'prose-headings:text-blue-400' },
  };
  return map[subjectId] || map.default;
};

export const RevisionSheet: React.FC = () => {
  const { topicId } = useParams<{ topicId: string }>();
  const navigate = useNavigate();

  // Find topic and parent subject
  const context = useMemo(() => {
    for (const sub of SUBJECTS) {
      const t = sub.topics.find(t => t.id === topicId);
      if (t) return { topic: t, subject: sub };
    }
    return null;
  }, [topicId]);

  useEffect(() => {
    if (context && topicId) {
      markSheetRead(topicId);
    }
  }, [context, topicId]);

  if (!context || !context.topic.content) {
    return <div className="p-8 text-center text-slate-400">Fiche introuvable</div>;
  }

  const { topic, subject } = context;
