import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { SUBJECTS } from '../data/content';
import { saveQuizScore } from '../services/storageService';
import { getTheme } from '../lib/theme';
import { PageTransition } from '../components/PageTransition';
import { X, Check, ArrowRight, RefreshCw, Calculator, CalculatorOff } from 'lucide-react';
import clsx from 'clsx';
import { motion, AnimatePresence } from 'framer-motion';

export const QuizSession: React.FC = () => {
  const { topicId } = useParams<{ topicId: string }>();
  const navigate = useNavigate();

  // Find the topic inside subjects and get subject for theming
  const context = SUBJECTS.flatMap(s => s.topics.map(t => ({ topic: t, subject: s }))).find(ctx => ctx.topic.id === topicId);
  const topic = context?.topic;
  const subject = context?.subject;

  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);

  if (!topic || !subject || topic.type !== 'quiz' || !topic.questions) {
    return <div className="p-8 text-center text-slate-400">Quiz introuvable</div>;
  }

  const theme = getTheme(subject.id);
  const currentQuestion = topic.questions[currentIndex];
  const progressPercent = ((currentIndex + (showResult ? 1 : 0)) / topic.questions.length) * 100;

  // Explicitly check for calculator permission. If undefined, assume allowed for now, unless specific tag implies otherwise.
  const isCalculatorAllowed = currentQuestion.calculatorAllowed !== false;

  const handleOptionClick = (index: number) => {
    if (isAnswered) return;
    setSelectedOption(index);
    setIsAnswered(true);

    if (index === currentQuestion.correctAnswer) {
      setScore(s => s + 1);
    }
  };

  const handleNext = () => {
    if (currentIndex < (topic.questions?.length || 0) - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setShowResult(true);
      const finalScore = Math.round(((score + (selectedOption === currentQuestion.correctAnswer ? 0 : 0)) / topic.questions!.length) * 100);
      saveQuizScore(topic.id, finalScore);
    }
  };

  if (showResult) {
    const finalScore = Math.round((score / topic.questions.length) * 100);
    return (
      <PageTransition className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-3xl p-8 text-center space-y-6 shadow-2xl">
          <motion.div 
            initial={{ scale: 0 }} animate={{ scale: 1 }}
            className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-slate-700"
          >
             <span className="text-4xl">🎉</span>
          </motion.div>

          <div>
            <h2 className="text-2xl font-bold text-white mb-2">Quiz terminé !</h2>
            <p className="text-slate-400">Tu as complété : <br/><span className={theme.text}>{topic.title}</span></p>
          </div>

          <div className="py-8 border-y border-slate-800">
             <motion.div 
                initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                className="text-6xl font-black text-white mb-2"
             >
                {finalScore}%
             </motion.div>
             <p className="text-sm text-slate-500 font-medium uppercase tracking-widest">Score final</p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => navigate(-1)} className="py-3 px-4 bg-slate-800 hover:bg-slate-700 text-white rounded-xl font-medium transition-colors">
                Retour
            </button>
            <button onClick={() => window.location.reload()} className={clsx("py-3 px-4 text-white rounded-xl font-medium transition-colors flex items-center justify-center gap-2", theme.background)}>
                <RefreshCw className="w-4 h-4" /> Réessayer
            </button>
          </div>
        </div>
      </PageTransition>
    );
  }

  return (
    <PageTransition className="min-h-screen bg-slate-950 flex flex-col">
      <div className="h-16 px-4 flex items-center justify-between border-b border-slate-800 bg-slate-950/50 backdrop-blur">
        <button onClick={() => navigate(-1)} className="p-2 -ml-2 text-slate-400 hover:text-white transition-colors">
            <X className="w-6 h-6" />
        </button>
        <div className="flex items-center gap-4">
            {/* Calculator Indicator */}
            <div className={clsx(
                "flex items-center gap-1.5 px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border",
                isCalculatorAllowed 
                    ? "bg-slate-800 border-slate-700 text-slate-400"
                    : "bg-red-500/10 border-red-500/30 text-red-400"
            )}>
                {isCalculatorAllowed ? <Calculator className="w-3 h-3" /> : <CalculatorOff className="w-3 h-3" />}
                <span>{isCalculatorAllowed ? 'Autorisée' : 'Interdite'}</span>
            </div>
            <div className="text-xs font-bold uppercase tracking-widest text-slate-500">
                {currentIndex + 1} / {topic.questions.length}
            </div>
        </div>
        <div className="w-8" /> 
      </div>

      <div className="h-1.5 bg-slate-900 w-full">
        <motion.div 
            className={clsx("h-full", theme.background)} 
            initial={{ width: 0 }}
            animate={{ width: `${progressPercent}%` }}
        />
      </div>

      <div className="flex-1 flex flex-col p-6 max-w-2xl mx-auto w-full">
        <AnimatePresence mode="wait">
            <motion.div 
                key={currentIndex}
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                className="flex-1 flex flex-col"
            >
                <h2 className="text-xl md:text-2xl font-bold text-white mb-8 leading-relaxed">
                    {currentQuestion.text}
                </h2>

                <div className="space-y-3 flex-1">
                    {currentQuestion.options.map((option, idx) => {
                        let stateClass = "bg-slate-800/50 border-slate-700 text-slate-300 hover:border-slate-500 hover:bg-slate-800";

                        if (isAnswered) {
                            if (idx === currentQuestion.correctAnswer) {
                                stateClass = "bg-emerald-500/10 border-emerald-500 text-emerald-400 ring-1 ring-emerald-500/50";
                            } else if (idx === selectedOption) {
                                stateClass = "bg-red-500/10 border-red-500 text-red-400";
                            } else {
                                stateClass = "opacity-50 grayscale bg-slate-900 border-slate-800";
                            }
                        }

                        return (
                            <button
                                key={idx}
                                onClick={() => handleOptionClick(idx)}
                                disabled={isAnswered}
                                className={clsx(
                                    "w-full p-5 text-left rounded-2xl border-2 transition-all duration-200 flex justify-between items-center group relative overflow-hidden",
                                    stateClass
                                )}
                            >
                                <span className="font-medium relative z-10">{option}</span>
                                {isAnswered && idx === currentQuestion.correctAnswer && <Check className="w-5 h-5 relative z-10" />}
                            </button>
                        );
                    })}
                </div>
            </motion.div>
        </AnimatePresence>

        <div className="mt-8 min-h-[120px]">
            <AnimatePresence>
                {isAnswered && (
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="space-y-4"
                    >
                        {currentQuestion.explanation && (
                            <div className={clsx("p-4 rounded-xl border bg-opacity-10 text-sm leading-relaxed", theme.border, theme.background, theme.text)}>
                                <strong className="block mb-1 text-xs uppercase opacity-70">Explication</strong> 
                                {currentQuestion.explanation}
                            </div>
                        )}
                        <button 
                            onClick={handleNext}
                            className={clsx("w-full py-4 text-white rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-transform active:scale-95", theme.background)}
                        >
                            {currentIndex === topic.questions.length - 1 ? 'Résultats' : 'Suivant'} <ArrowRight className="w-5 h-5" />
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
      </div>
    </PageTransition>
  );
};

