interface CardProps {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
  to?: string;
  gradient?: string; // e.g. "from-blue-600 to-indigo-700"
}

export const Card: React.FC<CardProps> = ({ children, className, onClick, to, gradient }) => {
  const baseStyles = "relative block bg-slate-800 rounded-xl border border-slate-700 overflow-hidden hover:border-slate-500 transition-all active:scale-[0.98] duration-200 shadow-sm";

  const content = (
    <>
      {gradient && (
        <div className={clsx("absolute inset-0 opacity-0 hover:opacity-10 transition-opacity bg-gradient-to-br", gradient)} />
      )}
      <div className="relative z-10 h-full">
        {children}
      </div>
    </>
  );

  if (to) {
    return (
      <Link to={to} className={clsx(baseStyles, "hover:shadow-lg", className)}>
        {content}
      </Link>
    );
  }

  return (
    <div onClick={onClick} className={clsx(baseStyles, onClick && "cursor-pointer", className)}>
      {content}
    </div>
  );
};

