import { Card } from '../components/ui/Card';

export const SubjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const subject = getSubjectById(id || '');
  const progress = getProgress();

  // Group topics by category
  const groupedTopics = useMemo<Record<string, Topic[]>>(() => {
    if (!subject) return {};
    const groups: Record<string, Topic[]> = {};

    subject.topics.forEach(topic => {
      const cat = topic.category || 'Général';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(topic);
    });

    return groups;
  }, [subject]);

  if (!subject) {
    return <div className="p-8 text-center text-slate-400">Matière introuvable</div>;
  }

  return (
    <div className="pb-24">
      {/* Header for Subject */}
      <div className={clsx("relative p-6 -mt-0", subject.color)}>
        <button 
          onClick={() => navigate('/')}
          className="absolute top-6 left-4 p-2 bg-black/20 rounded-full hover:bg-black/30 text-white transition-colors"
        >
          <ChevronLeft className="w-6 h-6" />
        </button>
        <div className="mt-8">
          <h1 className="text-3xl font-bold text-white mb-2">{subject.name}</h1>
          <p className="text-white/80 text-sm font-medium">
            {subject.topics.length} modules disponibles
          </p>
        </div>
      </div>

      {/* Topic List Grouped by Category */}
      <div className="p-4 space-y-6 -mt-4 relative z-10">
        {Object.entries(groupedTopics).map(([category, topics]) => (
          <div key={category} className="space-y-3">
             {category !== 'Général' && (
               <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider px-1 mt-2">
                 {category}
               </h2>
             )}

             {topics.map((topic) => {
                const isCompleted = progress.completedTopics.includes(topic.id);
                const score = progress.quizScores[topic.id];

                return (
                  <Card
                    key={topic.id}
                    to={topic.type === 'quiz' ? `/quiz/${topic.id}` : `/sheet/${topic.id}`}
                    className="flex items-center gap-4 p-4"
                  >
                    <div className={clsx(
                      "w-12 h-12 rounded-full flex items-center justify-center shrink-0 border border-slate-700",
                      isCompleted ? "bg-green-500/10 text-green-500" : "bg-slate-700/50 text-slate-400"
                    )}>
                      {isCompleted ? <CheckCircle2 className="w-6 h-6" /> : (
                        topic.type === 'quiz' ? <PlayCircle className="w-6 h-6" /> : <FileText className="w-6 h-6" />
                      )}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-start mb-1">
                          <h3 className="font-semibold text-slate-200 truncate pr-2">{topic.title}</h3>
                          {topic.type === 'quiz' && score !== undefined && (
                              <span className={clsx(
                                  "text-xs font-bold px-2 py-0.5 rounded",
                                  score >= 80 ? "bg-green-500/20 text-green-400" : "bg-yellow-500/20 text-yellow-400"
                              )}>
                                  {score}%
                              </span>
                          )}
                      </div>
                      <p className="text-xs text-slate-400 truncate">{topic.description}</p>
                    </div>
                  </Card>
                );
             })}
          </div>
        ))}

        {subject.topics.length === 0 && (
            <div className="text-center py-10">
                <p className="text-slate-500">Contenu à venir pour {subject.name}...</p>
            </div>
        )}
      </div>
    </div>
  );
};

